<template>
  <div class="container-fluid">
    <div class="row">
      <div class="col-12 col-md-12">
        <div class="row">
          <div class="col-12 col-md-8">
            <h2 class="my-3">
              <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="currentColor" class="bi bi-wrench-adjustable" viewBox="0 0 16 16">
                <path d="M16 4.5a4.492 4.492 0 0 1-1.703 3.526L13 5l2.959-1.11c.027.2.041.403.041.61Z"/>
                <path d="M11.5 9c.653 0 1.273-.139 1.833-.39L12 5.5 11 3l3.826-1.53A4.5 4.5 0 0 0 7.29 6.092l-6.116 5.096a2.583 2.583 0 1 0 3.638 3.638L9.908 8.71A4.49 4.49 0 0 0 11.5 9Zm-1.292-4.361-.596.893.809-.27a.25.25 0 0 1 .287.377l-.596.893.809-.27.158.475-1.5.5a.25.25 0 0 1-.287-.376l.596-.893-.809.27a.25.25 0 0 1-.287-.377l.596-.893-.809.27-.158-.475 1.5-.5a.25.25 0 0 1 .287.376ZM3 14a1 1 0 1 1 0-2 1 1 0 0 1 0 2Z"/>
              </svg>
              產品管理
            </h2>
          </div>
          <div class="col-12 col-md-2 my-auto mx-start">
            <select v-model.number="itemsPerPage" class="form-select" aria-label="Default select example">
              <option value=20 selected>每頁顯示數量</option>
              <option value=10>10</option>
              <option value=20>20</option>
              <option value=30>30</option>
            </select>
          </div>
          <div class="col-12 col-md-2 my-auto mx-start">
            <button @click="goAddProduct" class="btn btn-success w-100">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="currentColor" class="bi bi-plus-square-fill" viewBox="0 0 16 16">
                <path d="M2 0a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V2a2 2 0 0 0-2-2H2zm6.5 4.5v3h3a.5.5 0 0 1 0 1h-3v3a.5.5 0 0 1-1 0v-3h-3a.5.5 0 0 1 0-1h3v-3a.5.5 0 0 1 1 0z"/>
              </svg>
              <span class="p-3">添加新產品</span>
            </button>
          </div>
        </div>
        
        <div class="table-responsive-sm">
          <table class="table table-bordered table-striped table-hover table-dark text-center ">
            <thead>
              <tr class="d-none d-md-table-row">
                <th scope="col" class="col-2">產品ID</th>
                <th scope="col" class="col-2">產品名稱</th>
                <th scope="col" class="col-2">產品分類</th>
                <th scope="col" class="col-2">產品價格</th>
                <th scope="col" class="col-2">操作</th>
              </tr>
            </thead>
            <tbody>
              <tr v-for="(item) in paginatedItems.items" :key="item.id">
                
                  <th>{{ item.id }}</th>
                  <td>{{ item.productName }}</td>
                  <td>{{item.category}}</td>
                  <td>{{item.productPrice}}</td>
                  <td class="">
                    <button @click="editProduct(item.id)" class="btn btn-secondary mx-3">
                      編輯
                    </button>
                    <button @click="saveProductId(item.id)"  class="btn btn-danger" data-bs-toggle="modal" data-bs-target="#deleteItem">
                      刪除
                    </button>
                  </td>
              </tr>
            </tbody>
          </table>
          <nav aria-label="Page navigation example">
            <ul class="pagination justify-content-center">
              <li @click="goPreviousPage()" id="previous" class="page-item ">
                <a class="page-link" href="#">上一頁</a>
              </li>
              <div v-for="page in totalPages" :key="page">
                  <li  @click="changePage(page)" class="page-item"><a class="page-link" href="#">{{ page }}</a></li>
              </div>
              <li @click="goNextPage(currentPage)" id="next" class="page-item">
                <a class="page-link" href="#">下一頁</a>
              </li>
            </ul>
          </nav>
        </div>  
      </div>
    </div>
  </div>

  <div class="modal fade" id="deleteItem" tabindex="-1" aria-labelledby="deleteItemModalLabel" aria-hidden="true">
  <div class="modal-dialog modal-dialog-centered">
    <div class="modal-content">
      <div class="modal-header">
        <h5 class="modal-title" id="exampleModalLabel">警告</h5>
        <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button>
      </div>
      <div class="modal-body">
        確定要刪除此項產品嗎
      </div>
      <div class="modal-footer">
        <button type="button" class="btn btn-secondary" data-bs-dismiss="modal">關閉</button>
        <button @click="deleteProduct()" type="button" class="btn btn-primary" data-bs-dismiss="modal">確定</button>
      </div>
    </div>
  </div>
</div>

</template>

<script>
import {reactive,onMounted,toRefs,ref,onBeforeUpdate,watch,toRaw} from 'vue'
import axios from 'axios'
import {useRouter} from 'vue-router'
import {useBackendInfoTempStore} from '@/store/backendInfoTemp'
export default {
  name:'BackEndProducts',
  setup(){
    let backendProductStore=useBackendInfoTempStore()
    let router= useRouter()
    let products=reactive({items:{}})
    let itemsPerPage=ref(20)
    let totalPages=ref(0)
    let currentPage=ref(1)
    let paginatedItems=reactive({items:{}},{deep:true})

    function changePage(page){
      currentPage.value=page
      const startIndex = (currentPage.value -1) * itemsPerPage.value
      const endIndex = (currentPage.value* itemsPerPage.value)  
      paginatedItems.items=products.items.slice(startIndex,endIndex)
      let activeBtn=document.getElementsByClassName('page-item')
      let acitveBtnArray=Array.from(activeBtn)
      for(let i=0 ; i < acitveBtnArray.length ;i++){
        if(parseInt(acitveBtnArray[i].innerText) === page){
          acitveBtnArray[i].classList.add('active')
        }else{
          acitveBtnArray[i].classList.remove('active')
        }
      }
    }

    function goAddProduct(){
      router.push('addproduct')
    }
    
    onMounted(()=>{
      axios.get(`/getproducts?category=all`).then(
        response =>{
          products.items=response.data
          console.log(products)
          totalPages.value=Math.ceil(products.items.length/itemsPerPage.value)
          const startIndex = (currentPage.value -1) * itemsPerPage.value
          const endIndex = (currentPage.value* itemsPerPage.value)  
          paginatedItems.items=products.items.slice(startIndex,endIndex)
        }
      ).catch(
        error =>{
          console.log(error.message)
        }
      )
    })


    function editProduct(productId){
      for(let detail in products.items){
        if(products.items[detail].id ===productId){
          let editproduct =toRaw(products.items[detail])
          backendProductStore.saveProduct(editproduct)
        }
      }
      router.push('editproduct')
    }
    
    onBeforeUpdate(() => {
      totalPages.value=Math.ceil(products.items.length/itemsPerPage.value)
      const startIndex = (currentPage.value -1) * itemsPerPage.value
      const endIndex = (currentPage.value* itemsPerPage.value)
      paginatedItems.items=products.items.slice(startIndex,endIndex)  
      let previousbtn = document.getElementById('previous')
      let nextbtn = document.getElementById('next')
      if(currentPage.value===1){
        previousbtn.classList.add('disabled')
      }else {
        previousbtn.classList.remove('disabled') 
      }
      if(totalPages.value===currentPage.value){
        nextbtn.classList.add('disabled')
      }else{
        nextbtn.classList.remove('disabled')
      }
    })

    function goPreviousPage(){
      currentPage.value--
      let currentPageBtn=document.getElementsByClassName('page-item')
      let currentPageBtnArray=Array.from(currentPageBtn)
      for(let i=0 ; i < currentPageBtnArray.length ;i++){
        if(parseInt(currentPageBtnArray[i].innerText) === currentPage.value){
          currentPageBtnArray[i].classList.add('active')
        }else{
          currentPageBtnArray[i].classList.remove('active')
        }
      }

    }


    function deleteProduct(){
      let productId=backendProductStore.productId
      console.log(productId)
      axios.post('/deleteproductbyid',{'productId':productId},{headers:{'contentType':'application/json'}}).then(
        response =>{
          console.log(response.data)
          products.items=response.data
        }
      )
      .catch(
        error =>{
          console.log(error.message)
        }
      )
    }

    function saveProductId(productId){
      backendProductStore.saveProductId(productId)
    }


    watch(()=>products.items,()=>{
      console.log('products.items changed')
      totalPages.value=Math.ceil(products.items.length/itemsPerPage.value)
          const startIndex = (currentPage.value -1) * itemsPerPage.value
          const endIndex = (currentPage.value* itemsPerPage.value)  
          paginatedItems.items=products.items.slice(startIndex,endIndex)
    },{deep:true})


    function goNextPage(){
      currentPage.value++
      let currentPageBtn=document.getElementsByClassName('page-item')
      let currentPageBtnArray=Array.from(currentPageBtn)
      for(let i=0 ; i < currentPageBtnArray.length ;i++){
        if(parseInt(currentPageBtnArray[i].innerText) === currentPage.value){
          currentPageBtnArray[i].classList.add('active')
        }else{
          currentPageBtnArray[i].classList.remove('active')
        }
      }
    }

    return{
      ...toRefs(products),
      paginatedItems,
      totalPages,
      changePage,
      currentPage,
      itemsPerPage,
      goPreviousPage,
      goNextPage,
      goAddProduct,
      deleteProduct,
      editProduct,
      saveProductId
    }
  }
}
</script>

